var COURSE_PL_SW = [{day: 1, title: `Powitania i pierwsze słowa`, title_native: `Salamu na maneno ya kwanza`, focus: `Nauczysz się witać ludzi i zaczynać bardzo proste rozmowy. Przyda się to od pierwszych minut po przylocie do Nairobi, Dar es Salaam albo Zanzibaru.`, vocab: [{sw: `jambo`, pl: `cześć / dzień dobry`, ipa: `dżam-bo`},{sw: `habari`, pl: `co słychać / wiadomości`, ipa: `ha-ba-ri`},{sw: `nzuri`, pl: `dobrze`, ipa: `nzu-ri`},{sw: `asante`, pl: `dziękuję`, ipa: `a-san-te`},{sw: `tafadhali`, pl: `proszę`, ipa: `ta-fa-dha-li`},{sw: `ndiyo`, pl: `tak`, ipa: `ndi-jo`},{sw: `hapana`, pl: `nie`, ipa: `ha-pa-na`},{sw: `samahani`, pl: `przepraszam`, ipa: `sa-ma-ha-ni`},{sw: `karibu`, pl: `witaj / zapraszam`, ipa: `ka-ri-bu`},{sw: `kwaheri`, pl: `do widzenia`, ipa: `kwa-he-ri`}], phrases: [{sw: `Jambo!`, pl: `Cześć!`, ipa: `dżam-bo`},{sw: `Habari?`, pl: `Co słychać?`, ipa: `ha-ba-ri`},{sw: `Nzuri, asante.`, pl: `Dobrze, dziękuję.`, ipa: `nzu-ri a-san-te`},{sw: `Tafadhali.`, pl: `Proszę.`, ipa: `ta-fa-dha-li`},{sw: `Samahani.`, pl: `Przepraszam.`, ipa: `sa-ma-ha-ni`},{sw: `Kwaheri.`, pl: `Do widzenia.`, ipa: `kwa-he-ri`}], grammar: `W suahili powitania są bardzo ważne i często dłuższe niż w języku polskim. „Habari?” można rozumieć jako „Co słychać?”, a najprostsza odpowiedź to „Nzuri”. Słowo „karibu” usłyszysz bardzo często w hotelach, sklepach i restauracjach — oznacza zarówno „witaj”, jak i „zapraszam”.`, practice: [`Powiedz po suahili: „Cześć, co słychać?”`,`Odpowiedz na „Habari?” jednym krótkim zdaniem.`,`Przećwicz trzy razy: „Asante” i „Tafadhali”.`,`Wyobraź sobie, że wchodzisz do małego sklepu w Stone Town i witasz sprzedawcę.`,`Zapisz pięć słów z dzisiejszej lekcji, których użyjesz pierwszego dnia podróży.`]},{day: 2, title: `Przedstawianie się`, title_native: `Kujitambulisha`, focus: `Nauczysz się mówić, jak masz na imię i skąd jesteś. To przyda się podczas rozmów z kierowcą, gospodarzem pensjonatu albo innymi podróżnymi w Tanzanii i Kenii.`, vocab: [{sw: `jina`, pl: `imię`, ipa: `dżi-na`},{sw: `naitwa`, pl: `nazywam się`, ipa: `na-it-wa`},{sw: `mimi`, pl: `ja`, ipa: `mi-mi`},{sw: `wewe`, pl: `ty`, ipa: `we-we`},{sw: `kutoka`, pl: `pochodzić / z`, ipa: `ku-to-ka`},{sw: `Polandi`, pl: `Polska`, ipa: `po-lan-di`},{sw: `rafiki`, pl: `przyjaciel`, ipa: `ra-fi-ki`},{sw: `mgeni`, pl: `gość / obcokrajowiec`, ipa: `m-ge-ni`},{sw: `nchi`, pl: `kraj`, ipa: `n-czi`},{sw: `furaha`, pl: `radość / miło`, ipa: `fu-ra-ha`}], phrases: [{sw: `Jina langu ni Anna.`, pl: `Mam na imię Anna.`, ipa: `dżi-na lan-gu ni an-na`},{sw: `Naitwa Piotr.`, pl: `Nazywam się Piotr.`, ipa: `na-it-wa pjo-tr`},{sw: `Mimi ni kutoka Polandi.`, pl: `Jestem z Polski.`, ipa: `mi-mi ni ku-to-ka po-lan-di`},{sw: `Wewe unaitwa nani?`, pl: `Jak masz na imię?`, ipa: `we-we u-na-it-wa na-ni`},{sw: `Nimefurahi kukutana nawe.`, pl: `Miło cię poznać.`, ipa: `ni-me-fu-ra-hi ku-ku-ta-na na-we`},{sw: `Mimi ni mgeni hapa.`, pl: `Jestem tutaj gościem / turystą.`, ipa: `mi-mi ni m-ge-ni ha-pa`}], grammar: `W zdaniu „Jina langu ni...” słowo „langu” znaczy „moje” i odnosi się do „jina”, czyli imienia. W codziennej rozmowie możesz też powiedzieć prościej: „Naitwa...”. Pytanie „nani?” znaczy „kto?” i pojawia się w pytaniu o imię: „Unaitwa nani?”`, practice: [`Przedstaw się po suahili, używając „Naitwa...”.`,`Powiedz, że jesteś z Polski.`,`Zapytaj rozmówcę, jak ma na imię.`,`Ułóż krótką wymianę: powitanie, imię, kraj.`,`Wyobraź sobie rozmowę w hostelu w Aruszy i powiedz: „Miło cię poznać.”`]},{day: 3, title: `Podstawowe zwroty grzecznościowe`, title_native: `Maneno ya heshima`, focus: `Dziś skupisz się na uprzejmości, która jest bardzo ważna w kulturach suahili. Te zwroty pomogą ci dobrze wypaść w hotelu, na targu i w rozmowach z lokalnymi mieszkańcami.`, vocab: [{sw: `pole`, pl: `przykro mi / współczuję / spokojnie`, ipa: `po-le`},{sw: `sawa`, pl: `dobrze / w porządku`, ipa: `sa-wa`},{sw: `shukrani`, pl: `podziękowania`, ipa: `szu-kra-ni`},{sw: `heshima`, pl: `szacunek`, ipa: `he-szi-ma`},{sw: `bwana`, pl: `pan`, ipa: `bła-na`},{sw: `mama`, pl: `pani / mama`, ipa: `ma-ma`},{sw: `ndugu`, pl: `brat / siostra / osoba bliska`, ipa: `n-du-gu`},{sw: `subiri`, pl: `poczekaj`, ipa: `su-bi-ri`},{sw: `kidogo`, pl: `trochę`, ipa: `ki-do-go`},{sw: `hakuna`, pl: `nie ma`, ipa: `ha-ku-na`}], phrases: [{sw: `Asante sana.`, pl: `Bardzo dziękuję.`, ipa: `a-san-te sa-na`},{sw: `Karibu sana.`, pl: `Serdecznie witam / proszę bardzo.`, ipa: `ka-ri-bu sa-na`},{sw: `Pole sana.`, pl: `Bardzo mi przykro / spokojnie.`, ipa: `po-le sa-na`},{sw: `Sawa, asante.`, pl: `W porządku, dziękuję.`, ipa: `sa-wa a-san-te`},{sw: `Subiri kidogo, tafadhali.`, pl: `Proszę chwilę poczekać.`, ipa: `su-bi-ri ki-do-go ta-fa-dha-li`},{sw: `Hakuna shida.`, pl: `Nie ma problemu.`, ipa: `ha-ku-na szi-da`}], grammar: `„Sana” wzmacnia znaczenie słowa, podobnie jak polskie „bardzo”. „Asante sana” to „bardzo dziękuję”, a „karibu sana” brzmi cieplej niż samo „karibu”. Zwrot „hakuna shida” jest bardzo praktyczny i znaczy „nie ma problemu”.`, practice: [`Powiedz po suahili: „Bardzo dziękuję.”`,`Odpowiedz uprzejmie na czyjeś „Asante”.`,`Poproś kogoś, żeby chwilę poczekał.`,`Użyj „hakuna shida” w krótkiej sytuacji podróżnej.`,`Przećwicz różnicę między „asante” i „asante sana”.`]},{day: 4, title: `Liczby od 1 do 20`, title_native: `Nambari moja hadi ishirini`, focus: `Nauczysz się podstawowych liczb potrzebnych przy płaceniu, kupowaniu biletów i zamawianiu jedzenia. W Mombasie, Dar es Salaam czy Kampali liczby szybko staną się niezbędne.`, vocab: [{sw: `moja`, pl: `jeden`, ipa: `mo-dża`},{sw: `mbili`, pl: `dwa`, ipa: `m-bi-li`},{sw: `tatu`, pl: `trzy`, ipa: `ta-tu`},{sw: `nne`, pl: `cztery`, ipa: `n-ne`},{sw: `tano`, pl: `pięć`, ipa: `ta-no`},{sw: `sita`, pl: `sześć`, ipa: `si-ta`},{sw: `saba`, pl: `siedem`, ipa: `sa-ba`},{sw: `nane`, pl: `osiem`, ipa: `na-ne`},{sw: `tisa`, pl: `dziewięć`, ipa: `ti-sa`},{sw: `kumi`, pl: `dziesięć`, ipa: `ku-mi`}], phrases: [{sw: `Moja, tafadhali.`, pl: `Jedno, proszę.`, ipa: `mo-dża ta-fa-dha-li`},{sw: `Mbili, tafadhali.`, pl: `Dwa, proszę.`, ipa: `m-bi-li ta-fa-dha-li`},{sw: `Ninataka tatu.`, pl: `Chcę trzy.`, ipa: `ni-na-ta-ka ta-tu`},{sw: `Ni kiasi gani?`, pl: `Ile to kosztuje?`, ipa: `ni ki-a-si ga-ni`},{sw: `Kumi tu.`, pl: `Tylko dziesięć.`, ipa: `ku-mi tu`},{sw: `Nambari yangu ni mbili.`, pl: `Mój numer to dwa.`, ipa: `nam-ba-ri jan-gu ni m-bi-li`}], grammar: `Liczby w suahili są bardzo regularne i często używa się ich bez skomplikowanej odmiany. „Ninataka” znaczy „chcę” i możesz dodać po nim liczbę albo rzeczownik. „Tu” oznacza „tylko” i pojawia się często przy cenach lub ilościach.`, practice: [`Policz po suahili od 1 do 10.`,`Powiedz: „Chcę dwa.”`,`Zapytaj: „Ile to kosztuje?”`,`Wyobraź sobie, że kupujesz trzy butelki wody w kiosku.`,`Zapisz liczby 11–20, dodając „kumi na...” do znanych liczb.`]},{day: 5, title: `Proste pytania`, title_native: `Maswali rahisi`, focus: `Nauczysz się zadawać podstawowe pytania, które pomagają poruszać się po mieście. Przydadzą się na ulicy w Nairobi, na przystani w Zanzibarze i w lokalnym sklepie.`, vocab: [{sw: `nani`, pl: `kto`, ipa: `na-ni`},{sw: `nini`, pl: `co`, ipa: `ni-ni`},{sw: `wapi`, pl: `gdzie`, ipa: `wa-pi`},{sw: `lini`, pl: `kiedy`, ipa: `li-ni`},{sw: `kwa nini`, pl: `dlaczego`, ipa: `kwa ni-ni`},{sw: `vipi`, pl: `jak`, ipa: `vi-pi`},{sw: `hapa`, pl: `tutaj`, ipa: `ha-pa`},{sw: `pale`, pl: `tam`, ipa: `pa-le`},{sw: `sasa`, pl: `teraz`, ipa: `sa-sa`},{sw: `leo`, pl: `dzisiaj`, ipa: `le-o`}], phrases: [{sw: `Hii ni nini?`, pl: `Co to jest?`, ipa: `hi-i ni ni-ni`},{sw: `Uko wapi?`, pl: `Gdzie jesteś?`, ipa: `u-ko wa-pi`},{sw: `Choo kiko wapi?`, pl: `Gdzie jest toaleta?`, ipa: `czo-o ki-ko wa-pi`},{sw: `Unaenda wapi?`, pl: `Dokąd idziesz / jedziesz?`, ipa: `u-na-en-da wa-pi`},{sw: `Ni lini?`, pl: `Kiedy to jest?`, ipa: `ni li-ni`},{sw: `Kwa nini?`, pl: `Dlaczego?`, ipa: `kwa ni-ni`}], grammar: `W suahili słowa pytające często stoją na końcu zdania, jak w „Choo kiko wapi?” — dosłownie „Toaleta jest gdzie?”. „Hii ni nini?” jest bardzo przydatne, gdy nie znasz nazwy potrawy, przedmiotu albo miejsca. Nie bój się zadawać krótkich pytań — są naturalne i zrozumiałe.`, practice: [`Zapytaj po suahili: „Gdzie jest toaleta?”`,`Zapytaj: „Co to jest?”`,`Ułóż pytanie z „wapi”.`,`Ułóż pytanie z „lini”.`,`Wyobraź sobie, że jesteś na targu w Dar es Salaam i pytasz o nieznany owoc.`]},{day: 6, title: `Rodzina i ludzie`, title_native: `Familia na watu`, focus: `Nauczysz się mówić o osobach, rodzinie i towarzyszach podróży. To przydatne, gdy rezerwujesz pokój, przedstawiasz znajomych albo rozmawiasz z lokalną rodziną.`, vocab: [{sw: `familia`, pl: `rodzina`, ipa: `fa-mi-li-a`},{sw: `mtu`, pl: `osoba / człowiek`, ipa: `m-tu`},{sw: `watu`, pl: `ludzie`, ipa: `wa-tu`},{sw: `mama`, pl: `mama / pani`, ipa: `ma-ma`},{sw: `baba`, pl: `tata / pan`, ipa: `ba-ba`},{sw: `kaka`, pl: `brat`, ipa: `ka-ka`},{sw: `dada`, pl: `siostra`, ipa: `da-da`},{sw: `mtoto`, pl: `dziecko`, ipa: `m-to-to`},{sw: `watoto`, pl: `dzieci`, ipa: `wa-to-to`},{sw: `mke`, pl: `żona`, ipa: `m-ke`}], phrases: [{sw: `Huyu ni rafiki yangu.`, pl: `To jest mój przyjaciel.`, ipa: `hu-ju ni ra-fi-ki jan-gu`},{sw: `Huyu ni dada yangu.`, pl: `To jest moja siostra.`, ipa: `hu-ju ni da-da jan-gu`},{sw: `Tuko pamoja.`, pl: `Jesteśmy razem.`, ipa: `tu-ko pa-mo-dża`},{sw: `Ninasafiri na familia yangu.`, pl: `Podróżuję z moją rodziną.`, ipa: `ni-na-sa-fi-ri na fa-mi-li-a jan-gu`},{sw: `Watoto wako wapi?`, pl: `Gdzie są dzieci?`, ipa: `wa-to-to wa-ko wa-pi`},{sw: `Mimi niko peke yangu.`, pl: `Jestem sam / sama.`, ipa: `mi-mi ni-ko pe-ke jan-gu`}], grammar: `„Yangu” oznacza „mój / moja / moje” w wielu praktycznych zwrotach, np. „rafiki yangu” — mój przyjaciel. „Huyu” znaczy „ta osoba / ten człowiek tutaj” i jest używane przy przedstawianiu ludzi. W liczbie mnogiej „mtu” zmienia się na „watu”, co warto zapamiętać jako bardzo częstą parę.`, practice: [`Przedstaw swojego przyjaciela po suahili.`,`Powiedz, że podróżujesz z rodziną.`,`Powiedz, że jesteś sam / sama.`,`Zapytaj, gdzie są dzieci.`,`Ułóż trzy zdania z „yangu”.`]},{day: 7, title: `Czas, dni i plan dnia`, title_native: `Muda, siku na mpango`, focus: `Nauczysz się mówić o czasie, dzisiejszym dniu i prostych planach. To pomoże ci umawiać transport, wycieczki i spotkania podczas pobytu w krajach Afryki Wschodniej.`, vocab: [{sw: `muda`, pl: `czas`, ipa: `mu-da`},{sw: `saa`, pl: `godzina / zegar`, ipa: `sa-a`},{sw: `siku`, pl: `dzień`, ipa: `si-ku`},{sw: `leo`, pl: `dzisiaj`, ipa: `le-o`},{sw: `kesho`, pl: `jutro`, ipa: `ke-szo`},{sw: `jana`, pl: `wczoraj`, ipa: `dża-na`},{sw: `asubuhi`, pl: `rano`, ipa: `a-su-bu-hi`},{sw: `mchana`, pl: `popołudnie / dzień`, ipa: `m-cza-na`},{sw: `jioni`, pl: `wieczór`, ipa: `dżi-o-ni`},{sw: `usiku`, pl: `noc`, ipa: `u-si-ku`}], phrases: [{sw: `Ni saa ngapi?`, pl: `Która godzina?`, ipa: `ni sa-a nga-pi`},{sw: `Leo ninaenda mjini.`, pl: `Dzisiaj jadę do miasta.`, ipa: `le-o ni-na-en-da m-dżi-ni`},{sw: `Kesho nina safari.`, pl: `Jutro mam podróż.`, ipa: `ke-szo ni-na sa-fa-ri`},{sw: `Tutaonana jioni.`, pl: `Zobaczymy się wieczorem.`, ipa: `tu-ta-o-na-na dżi-o-ni`},{sw: `Nina muda kidogo.`, pl: `Mam trochę czasu.`, ipa: `ni-na mu-da ki-do-go`},{sw: `Sina muda sasa.`, pl: `Nie mam teraz czasu.`, ipa: `si-na mu-da sa-sa`}], grammar: `„Nina” znaczy „mam”, a „sina” znaczy „nie mam”. W suahili czas przyszły często oznacza cząstka „ta”, jak w „tutaonana” — zobaczymy się. Słowo „safari” nie oznacza tylko wyprawy na zwierzęta; w suahili znaczy ogólnie „podróż”.`, practice: [`Zapytaj po suahili: „Która godzina?”`,`Powiedz: „Dzisiaj jadę do miasta.”`,`Powiedz: „Jutro mam podróż.”`,`Ułóż zdanie z „asubuhi”.`,`Ułóż zdanie z „jioni”.`]},{day: 8, title: `Na lotnisku`, title_native: `Uwanja wa ndege`, focus: `Nauczysz się słów i zwrotów potrzebnych po przylocie na lotnisko w Nairobi, Dar es Salaam lub Zanzibarze. Skupimy się na bagażu, paszporcie i prostych prośbach.`, vocab: [{sw: `uwanja wa ndege`, pl: `lotnisko`, ipa: `u-wan-dża wa n-de-ge`},{sw: `pasipoti`, pl: `paszport`, ipa: `pa-si-po-ti`},{sw: `mizigo`, pl: `bagaże`, ipa: `mi-zi-go`},{sw: `tiketi`, pl: `bilet`, ipa: `ti-ke-ti`},{sw: `ndege`, pl: `samolot`, ipa: `n-de-ge`},{sw: `kuwasili`, pl: `przylot / przybyć`, ipa: `ku-wa-si-li`},{sw: `kuondoka`, pl: `odlot / odejść`, ipa: `ku-on-do-ka`},{sw: `forodha`, pl: `odprawa celna`, ipa: `fo-ro-dha`},{sw: `mstari`, pl: `kolejka`, ipa: `m-sta-ri`},{sw: `msaada`, pl: `pomoc`, ipa: `m-sa-a-da`}], phrases: [{sw: `Pasipoti yangu iko hapa.`, pl: `Mój paszport jest tutaj.`, ipa: `pa-si-po-ti jan-gu i-ko ha-pa`},{sw: `Mizigo yangu iko wapi?`, pl: `Gdzie jest mój bagaż?`, ipa: `mi-zi-go jan-gu i-ko wa-pi`},{sw: `Nahitaji msaada.`, pl: `Potrzebuję pomocy.`, ipa: `na-hi-ta-dżi m-sa-a-da`},{sw: `Nina tiketi.`, pl: `Mam bilet.`, ipa: `ni-na ti-ke-ti`},{sw: `Ndege imechelewa.`, pl: `Samolot jest opóźniony.`, ipa: `n-de-ge i-me-cze-le-wa`},{sw: `Forodha iko wapi?`, pl: `Gdzie jest odprawa celna?`, ipa: `fo-ro-dha i-ko wa-pi`}], grammar: `„Yangu” znasz już z wyrażeń typu „mój”. Przy rzeczach często używa się „iko” — „jest / znajduje się”. „Nahitaji” znaczy „potrzebuję” i jest jednym z najważniejszych czasowników dla podróżnika.`, practice: [`Powiedz, że potrzebujesz pomocy.`,`Zapytaj, gdzie jest twój bagaż.`,`Powiedz, że masz bilet.`,`Wyobraź sobie, że samolot jest opóźniony i informujesz o tym znajomego.`,`Zapytaj pracownika lotniska, gdzie jest odprawa celna.`]},{day: 9, title: `Transport z lotniska`, title_native: `Usafiri kutoka uwanja wa ndege`, focus: `Nauczysz się rozmawiać o taksówce, autobusie i trasie z lotniska do hotelu. Przyda się to szczególnie po przylocie, gdy chcesz szybko i bezpiecznie dotrzeć do miejsca noclegu.`, vocab: [{sw: `teksi`, pl: `taksówka`, ipa: `tek-si`},{sw: `basi`, pl: `autobus`, ipa: `ba-si`},{sw: `dereva`, pl: `kierowca`, ipa: `de-re-va`},{sw: `hoteli`, pl: `hotel`, ipa: `ho-te-li`},{sw: `bei`, pl: `cena`, ipa: `be-i`},{sw: `barabara`, pl: `droga / ulica`, ipa: `ba-ra-ba-ra`},{sw: `karibu`, pl: `blisko`, ipa: `ka-ri-bu`},{sw: `mbali`, pl: `daleko`, ipa: `m-ba-li`},{sw: `haraka`, pl: `szybko`, ipa: `ha-ra-ka`},{sw: `salama`, pl: `bezpiecznie`, ipa: `sa-la-ma`}], phrases: [{sw: `Nahitaji teksi.`, pl: `Potrzebuję taksówki.`, ipa: `na-hi-ta-dżi tek-si`},{sw: `Naenda hoteli.`, pl: `Jadę do hotelu.`, ipa: `na-en-da ho-te-li`},{sw: `Bei ni kiasi gani?`, pl: `Jaka jest cena?`, ipa: `be-i ni ki-a-si ga-ni`},{sw: `Ni mbali?`, pl: `Czy to daleko?`, ipa: `ni m-ba-li`},{sw: `Tafadhali, polepole.`, pl: `Proszę, powoli.`, ipa: `ta-fa-dha-li po-le-po-le`},{sw: `Naomba risiti.`, pl: `Poproszę paragon.`, ipa: `na-om-ba ri-si-ti`}], grammar: `„Naenda” oznacza „idę / jadę” i jest bardzo użyteczne przy podawaniu celu podróży. „Naomba” to grzeczne „proszę o / poproszę” i brzmi uprzejmie w sklepach, taksówkach i restauracjach. „Polepole” znaczy „powoli” i może być przydatne, gdy kierowca jedzie zbyt szybko.`, practice: [`Powiedz kierowcy: „Jadę do hotelu.”`,`Zapytaj o cenę przejazdu.`,`Zapytaj, czy hotel jest daleko.`,`Poproś kierowcę, żeby jechał powoli.`,`Poproś o paragon.`]},{day: 10, title: `Zameldowanie w hotelu`, title_native: `Kuingia hotelini`, focus: `Nauczysz się podstawowych zwrotów do zameldowania w hotelu lub pensjonacie. To przyda się w recepcji w Aruszy, Stone Town, Mombasie albo Dar es Salaam.`, vocab: [{sw: `mapokezi`, pl: `recepcja`, ipa: `ma-po-ke-zi`},{sw: `chumba`, pl: `pokój`, ipa: `czum-ba`},{sw: `ufunguo`, pl: `klucz`, ipa: `u-fun-gu-o`},{sw: `kitanda`, pl: `łóżko`, ipa: `ki-tan-da`},{sw: `bafu`, pl: `łazienka`, ipa: `ba-fu`},{sw: `hifadhi`, pl: `rezerwacja`, ipa: `hi-fa-dhi`},{sw: `jina`, pl: `imię / nazwisko`, ipa: `dżi-na`},{sw: `usiku`, pl: `noc`, ipa: `u-si-ku`},{sw: `gharama`, pl: `koszt`, ipa: `gha-ra-ma`},{sw: `malipo`, pl: `płatność`, ipa: `ma-li-po`}], phrases: [{sw: `Nina hifadhi.`, pl: `Mam rezerwację.`, ipa: `ni-na hi-fa-dhi`},{sw: `Jina langu ni Kowalski.`, pl: `Moje nazwisko to Kowalski.`, ipa: `dżi-na lan-gu ni ko-wal-ski`},{sw: `Nahitaji chumba kimoja.`, pl: `Potrzebuję jednego pokoju.`, ipa: `na-hi-ta-dżi czum-ba ki-mo-dża`},{sw: `Chumba kina bafu?`, pl: `Czy pokój ma łazienkę?`, ipa: `czum-ba ki-na ba-fu`},{sw: `Ufunguo uko wapi?`, pl: `Gdzie jest klucz?`, ipa: `u-fun-gu-o u-ko wa-pi`},{sw: `Nitalipa sasa.`, pl: `Zapłacę teraz.`, ipa: `ni-ta-li-pa sa-sa`}], grammar: `„Kina” oznacza „ma / posiada” dla wielu rzeczowników, np. „chumba kina bafu” — pokój ma łazienkę. „Nitalipa” zawiera przyszłość „ta” i znaczy „zapłacę”. W hotelu możesz mówić krótkimi zdaniami; ważniejsza jest jasność niż idealna gramatyka.`, practice: [`Powiedz w recepcji, że masz rezerwację.`,`Podaj swoje nazwisko, używając „Jina langu ni...”.`,`Zapytaj, czy pokój ma łazienkę.`,`Zapytaj, gdzie jest klucz.`,`Powiedz, że zapłacisz teraz.`]},{day: 11, title: `W pokoju hotelowym`, title_native: `Chumbani hotelini`, focus: `Nauczysz się zgłaszać proste problemy z pokojem hotelowym. To pomoże ci poprosić o ręcznik, wodę, klimatyzację lub naprawę.`, vocab: [{sw: `taulo`, pl: `ręcznik`, ipa: `ta-u-lo`},{sw: `maji`, pl: `woda`, ipa: `ma-dżi`},{sw: `kiyoyozi`, pl: `klimatyzacja`, ipa: `ki-jo-jo-zi`},{sw: `dirisha`, pl: `okno`, ipa: `di-ri-sza`},{sw: `mlango`, pl: `drzwi`, ipa: `m-lan-go`},{sw: `taa`, pl: `światło / lampa`, ipa: `ta-a`},{sw: `safi`, pl: `czysty`, ipa: `sa-fi`},{sw: `chafu`, pl: `brudny`, ipa: `cza-fu`},{sw: `tatizo`, pl: `problem`, ipa: `ta-ti-zo`},{sw: `fanya kazi`, pl: `działać / pracować`, ipa: `fa-nja ka-zi`}], phrases: [{sw: `Kuna tatizo.`, pl: `Jest problem.`, ipa: `ku-na ta-ti-zo`},{sw: `Kiyoyozi hakifanyi kazi.`, pl: `Klimatyzacja nie działa.`, ipa: `ki-jo-jo-zi ha-ki-fa-nji ka-zi`},{sw: `Nahitaji taulo.`, pl: `Potrzebuję ręcznika.`, ipa: `na-hi-ta-dżi ta-u-lo`},{sw: `Maji hayapo.`, pl: `Nie ma wody.`, ipa: `ma-dżi ha-ja-po`},{sw: `Chumba si safi.`, pl: `Pokój nie jest czysty.`, ipa: `czum-ba si sa-fi`},{sw: `Tafadhali, msaidie.`, pl: `Proszę, pomóżcie.`, ipa: `ta-fa-dha-li m-sa-i-di-e`}], grammar: `„Kuna” znaczy „jest / znajduje się” i często używa się go do mówienia o problemie: „Kuna tatizo”. Przeczenie może wyglądać różnie, ale w praktycznych zwrotach zapamiętaj gotowe formy: „hakifanyi kazi” — nie działa, „hayapo” — nie ma ich. W hotelu uprzejme „tafadhali” bardzo łagodzi zgłoszenie problemu.`, practice: [`Powiedz, że jest problem.`,`Powiedz, że klimatyzacja nie działa.`,`Poproś o ręcznik.`,`Powiedz, że pokój nie jest czysty.`,`Wyobraź sobie rozmowę z recepcją i użyj „tafadhali”.`]},{day: 12, title: `Zamawianie kawy i śniadania`, title_native: `Kuagiza kahawa na kifungua kinywa`, focus: `Nauczysz się zamawiać kawę, herbatę i proste śniadanie w kawiarni. Scena pasuje do poranka w Stone Town, Dar es Salaam albo Mombasie.`, vocab: [{sw: `kahawa`, pl: `kawa`, ipa: `ka-ha-wa`},{sw: `chai`, pl: `herbata`, ipa: `cza-i`},{sw: `maziwa`, pl: `mleko`, ipa: `ma-zi-wa`},{sw: `sukari`, pl: `cukier`, ipa: `su-ka-ri`},{sw: `mkate`, pl: `chleb`, ipa: `m-ka-te`},{sw: `mayai`, pl: `jajka`, ipa: `ma-ja-i`},{sw: `matunda`, pl: `owoce`, ipa: `ma-tun-da`},{sw: `kifungua kinywa`, pl: `śniadanie`, ipa: `ki-fun-gu-a ki-nju-wa`},{sw: `baridi`, pl: `zimny`, ipa: `ba-ri-di`},{sw: `moto`, pl: `gorący`, ipa: `mo-to`}], phrases: [{sw: `Naomba kahawa.`, pl: `Poproszę kawę.`, ipa: `na-om-ba ka-ha-wa`},{sw: `Naomba chai bila sukari.`, pl: `Poproszę herbatę bez cukru.`, ipa: `na-om-ba cza-i bi-la su-ka-ri`},{sw: `Kahawa na maziwa, tafadhali.`, pl: `Kawa z mlekiem, proszę.`, ipa: `ka-ha-wa na ma-zi-wa ta-fa-dha-li`},{sw: `Nataka mayai mawili.`, pl: `Chcę dwa jajka.`, ipa: `na-ta-ka ma-ja-i ma-wi-li`},{sw: `Kuna matunda?`, pl: `Czy są owoce?`, ipa: `ku-na ma-tun-da`},{sw: `Ni moto sana.`, pl: `To jest bardzo gorące.`, ipa: `ni mo-to sa-na`}], grammar: `„Bila” znaczy „bez”, więc „bila sukari” to „bez cukru”. „Na” znaczy „i” albo „z”, zależnie od kontekstu: „kahawa na maziwa” to kawa z mlekiem. Przy zamawianiu możesz używać „naomba” jako uprzejmego „poproszę”.`, practice: [`Zamów kawę z mlekiem.`,`Zamów herbatę bez cukru.`,`Zapytaj, czy są owoce.`,`Powiedz, że coś jest bardzo gorące.`,`Ułóż krótkie zamówienie śniadaniowe z dwoma rzeczami.`]},{day: 13, title: `W restauracji`, title_native: `Mgahawani`, focus: `Nauczysz się zamawiać jedzenie i pytać o menu. Przyda się to w lokalnej restauracji w Tanzanii, Kenii lub Ugandzie, zwłaszcza gdy chcesz spróbować dań regionalnych.`, vocab: [{sw: `mgahawa`, pl: `restauracja`, ipa: `m-ga-ha-wa`},{sw: `menyu`, pl: `menu`, ipa: `me-nju`},{sw: `chakula`, pl: `jedzenie`, ipa: `cza-ku-la`},{sw: `wali`, pl: `ryż`, ipa: `wa-li`},{sw: `nyama`, pl: `mięso`, ipa: `nja-ma`},{sw: `samaki`, pl: `ryba`, ipa: `sa-ma-ki`},{sw: `kuku`, pl: `kurczak`, ipa: `ku-ku`},{sw: `mboga`, pl: `warzywa`, ipa: `m-bo-ga`},{sw: `ladha`, pl: `smak`, ipa: `la-dha`},{sw: `bili`, pl: `rachunek`, ipa: `bi-li`}], phrases: [{sw: `Naomba menyu.`, pl: `Poproszę menu.`, ipa: `na-om-ba me-nju`},{sw: `Ninataka wali na samaki.`, pl: `Chcę ryż z rybą.`, ipa: `ni-na-ta-ka wa-li na sa-ma-ki`},{sw: `Kuna chakula cha mboga?`, pl: `Czy jest jedzenie wegetariańskie?`, ipa: `ku-na cza-ku-la cza m-bo-ga`},{sw: `Hii ni tamu.`, pl: `To jest smaczne.`, ipa: `hi-i ni ta-mu`},{sw: `Naomba bili.`, pl: `Poproszę rachunek.`, ipa: `na-om-ba bi-li`},{sw: `Nitalipa kwa kadi.`, pl: `Zapłacę kartą.`, ipa: `ni-ta-li-pa kwa ka-di`}], grammar: `„Cha” często łączy rzeczowniki i można je rozumieć jako „z / dla / typu”, np. „chakula cha mboga” — jedzenie warzywne. „Tamu” znaczy „smaczne” lub „słodkie”, zależnie od kontekstu. „Kwa” jest bardzo elastyczne: w „kwa kadi” oznacza „kartą”.`, practice: [`Poproś o menu.`,`Zamów ryż z rybą.`,`Zapytaj o jedzenie wegetariańskie.`,`Powiedz, że jedzenie jest smaczne.`,`Poproś o rachunek i powiedz, że zapłacisz kartą.`]},{day: 14, title: `Smaki, preferencje i alergie`, title_native: `Ladha, mapendeleo na mzio`, focus: `Nauczysz się mówić, co lubisz, czego nie jesz i na co musisz uważać. To ważne, gdy próbujesz lokalnych potraw, takich jak pilau, ugali, chapati czy samaki.`, vocab: [{sw: `napenda`, pl: `lubię`, ipa: `na-pen-da`},{sw: `sipendi`, pl: `nie lubię`, ipa: `si-pen-di`},{sw: `mzio`, pl: `alergia`, ipa: `m-zi-o`},{sw: `karanga`, pl: `orzeszki ziemne`, ipa: `ka-ran-ga`},{sw: `maziwa`, pl: `mleko`, ipa: `ma-zi-wa`},{sw: `pilipili`, pl: `chili / ostra papryka`, ipa: `pi-li-pi-li`},{sw: `chumvi`, pl: `sól`, ipa: `czum-vi`},{sw: `tamu`, pl: `smaczny / słodki`, ipa: `ta-mu`},{sw: `chungu`, pl: `gorzki`, ipa: `czun-gu`},{sw: `kali`, pl: `ostry / mocny`, ipa: `ka-li`}], phrases: [{sw: `Napenda chakula hiki.`, pl: `Lubię to jedzenie.`, ipa: `na-pen-da cza-ku-la hi-ki`},{sw: `Sipendi pilipili.`, pl: `Nie lubię chili.`, ipa: `si-pen-di pi-li-pi-li`},{sw: `Nina mzio wa karanga.`, pl: `Mam alergię na orzeszki ziemne.`, ipa: `ni-na m-zi-o wa ka-ran-ga`},{sw: `Bila pilipili, tafadhali.`, pl: `Bez chili, proszę.`, ipa: `bi-la pi-li-pi-li ta-fa-dha-li`},{sw: `Ni kali sana.`, pl: `To jest bardzo ostre.`, ipa: `ni ka-li sa-na`},{sw: `Chumvi kidogo tu.`, pl: `Tylko trochę soli.`, ipa: `czum-vi ki-do-go tu`}], grammar: `„Napenda” znaczy „lubię”, a „sipendi” to przeczenie: „nie lubię”. Konstrukcja „mzio wa...” oznacza „alergia na...”. Przy jedzeniu warto mówić jasno i prosto, zwłaszcza przy alergiach: „Nina mzio wa karanga” jest zdaniem, które może być bardzo ważne.`, practice: [`Powiedz, że lubisz to jedzenie.`,`Powiedz, że nie lubisz chili.`,`Powiedz, że masz alergię na orzeszki ziemne.`,`Poproś o jedzenie bez chili.`,`Powiedz, że coś jest bardzo ostre.`]},{day: 15, title: `Na targu`, title_native: `Sokoni`, focus: `Nauczysz się kupować owoce, pamiątki i drobne produkty na targu. Ta lekcja pasuje do kolorowych targów w Dar es Salaam, Aruszy, Mombasie i Stone Town.`, vocab: [{sw: `soko`, pl: `targ`, ipa: `so-ko`},{sw: `muuzaji`, pl: `sprzedawca`, ipa: `mu-u-za-dżi`},{sw: `matunda`, pl: `owoce`, ipa: `ma-tun-da`},{sw: `ndizi`, pl: `banany`, ipa: `n-di-zi`},{sw: `embe`, pl: `mango`, ipa: `em-be`},{sw: `bei`, pl: `cena`, ipa: `be-i`},{sw: `ghali`, pl: `drogi`, ipa: `gha-li`},{sw: `nafuu`, pl: `tani / przystępny`, ipa: `na-fu-u`},{sw: `pesa`, pl: `pieniądze`, ipa: `pe-sa`},{sw: `mfuko`, pl: `torba`, ipa: `m-fu-ko`}], phrases: [{sw: `Bei gani?`, pl: `Jaka cena?`, ipa: `be-i ga-ni`},{sw: `Hii ni ghali.`, pl: `To jest drogie.`, ipa: `hi-i ni gha-li`},{sw: `Unaweza kupunguza bei?`, pl: `Czy możesz obniżyć cenę?`, ipa: `u-na-we-za ku-pun-gu-za be-i`},{sw: `Naomba ndizi tano.`, pl: `Poproszę pięć bananów.`, ipa: `na-om-ba n-di-zi ta-no`},{sw: `Nina pesa kidogo.`, pl: `Mam mało pieniędzy.`, ipa: `ni-na pe-sa ki-do-go`},{sw: `Naomba mfuko.`, pl: `Poproszę torbę.`, ipa: `na-om-ba m-fu-ko`}], grammar: `Na targu często używa się krótkich zdań i uprzejmego tonu. „Unaweza...?” znaczy „czy możesz...?” i jest bardzo przydatne w negocjacjach. „Kupunguza bei” oznacza „obniżyć cenę”, ale używaj tego z uśmiechem i szacunkiem.`, practice: [`Zapytaj o cenę mango.`,`Powiedz, że coś jest drogie.`,`Poproś o pięć bananów.`,`Zapytaj, czy sprzedawca może obniżyć cenę.`,`Poproś o torbę.`]},{day: 16, title: `Płacenie i pieniądze`, title_native: `Kulipa na pesa`, focus: `Nauczysz się rozmawiać o gotówce, karcie i reszcie. To praktyczne w sklepach, restauracjach, taksówkach i na lokalnych targach.`, vocab: [{sw: `kulipa`, pl: `płacić`, ipa: `ku-li-pa`},{sw: `pesa taslimu`, pl: `gotówka`, ipa: `pe-sa tas-li-mu`},{sw: `kadi`, pl: `karta`, ipa: `ka-di`},{sw: `risiti`, pl: `paragon`, ipa: `ri-si-ti`},{sw: `chenji`, pl: `reszta`, ipa: `czen-dżi`},{sw: `benki`, pl: `bank`, ipa: `ben-ki`},{sw: `ATM`, pl: `bankomat`, ipa: `a-ti-em`},{sw: `sarafu`, pl: `moneta`, ipa: `sa-ra-fu`},{sw: `noti`, pl: `banknot`, ipa: `no-ti`},{sw: `gharama`, pl: `koszt`, ipa: `gha-ra-ma`}], phrases: [{sw: `Nitalipa kwa pesa taslimu.`, pl: `Zapłacę gotówką.`, ipa: `ni-ta-li-pa kwa pe-sa tas-li-mu`},{sw: `Nitalipa kwa kadi.`, pl: `Zapłacę kartą.`, ipa: `ni-ta-li-pa kwa ka-di`},{sw: `Naomba chenji.`, pl: `Poproszę resztę.`, ipa: `na-om-ba czen-dżi`},{sw: `Naomba risiti.`, pl: `Poproszę paragon.`, ipa: `na-om-ba ri-si-ti`},{sw: `ATM iko wapi?`, pl: `Gdzie jest bankomat?`, ipa: `a-ti-em i-ko wa-pi`},{sw: `Gharama ni kiasi gani?`, pl: `Jaki jest koszt?`, ipa: `gha-ra-ma ni ki-a-si ga-ni`}], grammar: `„Kwa” jest używane przy sposobie płatności: „kwa kadi” — kartą, „kwa pesa taslimu” — gotówką. „Naomba” sprawia, że prośba brzmi uprzejmie. W wielu miejscach warto zapytać wcześniej, czy karta jest akceptowana, bo gotówka nadal bywa najwygodniejsza.`, practice: [`Powiedz, że zapłacisz gotówką.`,`Powiedz, że zapłacisz kartą.`,`Poproś o resztę.`,`Zapytaj, gdzie jest bankomat.`,`Poproś o paragon.`]},{day: 17, title: `Kierunki i orientacja`, title_native: `Mielekeo na kutafuta njia`, focus: `Nauczysz się pytać o drogę i rozumieć proste wskazówki. Przyda się to w wąskich uliczkach Stone Town, centrum Nairobi albo przy dworcu autobusowym.`, vocab: [{sw: `njia`, pl: `droga`, ipa: `n-dżi-a`},{sw: `kushoto`, pl: `w lewo`, ipa: `ku-szo-to`},{sw: `kulia`, pl: `w prawo`, ipa: `ku-li-a`},{sw: `moja kwa moja`, pl: `prosto`, ipa: `mo-dża kwa mo-dża`},{sw: `karibu`, pl: `blisko`, ipa: `ka-ri-bu`},{sw: `mbali`, pl: `daleko`, ipa: `m-ba-li`},{sw: `hapa`, pl: `tutaj`, ipa: `ha-pa`},{sw: `pale`, pl: `tam`, ipa: `pa-le`},{sw: `mbele`, pl: `z przodu / dalej`, ipa: `m-be-le`},{sw: `nyuma`, pl: `z tyłu`, ipa: `nju-ma`}], phrases: [{sw: `Naomba njia ya hoteli.`, pl: `Proszę o drogę do hotelu.`, ipa: `na-om-ba n-dżi-a ja ho-te-li`},{sw: `Nenda moja kwa moja.`, pl: `Idź prosto.`, ipa: `nen-da mo-dża kwa mo-dża`},{sw: `Geuka kushoto.`, pl: `Skręć w lewo.`, ipa: `ge-u-ka ku-szo-to`},{sw: `Geuka kulia.`, pl: `Skręć w prawo.`, ipa: `ge-u-ka ku-li-a`},{sw: `Ni karibu hapa?`, pl: `Czy to blisko stąd?`, ipa: `ni ka-ri-bu ha-pa`},{sw: `Sijui njia.`, pl: `Nie znam drogi.`, ipa: `si-dżu-i n-dżi-a`}], grammar: `Tryb polecenia jest w suahili często krótki: „Nenda” — idź, „Geuka” — skręć. „Njia ya...” oznacza „droga do...”. Przy pytaniu o kierunek możesz zacząć od „samahani”, żeby zabrzmieć uprzejmie.`, practice: [`Zapytaj o drogę do hotelu.`,`Powiedz komuś: „Idź prosto.”`,`Powiedz: „Skręć w lewo.”`,`Zapytaj, czy to blisko.`,`Powiedz, że nie znasz drogi.`]},{day: 18, title: `Transport publiczny`, title_native: `Usafiri wa umma`, focus: `Nauczysz się kupować bilety i pytać o autobus, prom lub minibus. W krajach suahili spotkasz różne formy transportu, od daladala po promy na Zanzibar.`, vocab: [{sw: `usafiri`, pl: `transport`, ipa: `u-sa-fi-ri`},{sw: `basi`, pl: `autobus`, ipa: `ba-si`},{sw: `daladala`, pl: `lokalny minibus`, ipa: `da-la-da-la`},{sw: `kituo`, pl: `przystanek / stacja`, ipa: `ki-tu-o`},{sw: `tiketi`, pl: `bilet`, ipa: `ti-ke-ti`},{sw: `feri`, pl: `prom`, ipa: `fe-ri`},{sw: `treni`, pl: `pociąg`, ipa: `tre-ni`},{sw: `safari`, pl: `podróż`, ipa: `sa-fa-ri`},{sw: `kuondoka`, pl: `odjeżdżać / odchodzić`, ipa: `ku-on-do-ka`},{sw: `kuwasili`, pl: `przyjeżdżać / przybywać`, ipa: `ku-wa-si-li`}], phrases: [{sw: `Kituo cha basi kiko wapi?`, pl: `Gdzie jest przystanek autobusowy?`, ipa: `ki-tu-o cza ba-si ki-ko wa-pi`},{sw: `Naomba tiketi moja.`, pl: `Poproszę jeden bilet.`, ipa: `na-om-ba ti-ke-ti mo-dża`},{sw: `Basi linaondoka lini?`, pl: `Kiedy odjeżdża autobus?`, ipa: `ba-si li-na-on-do-ka li-ni`},{sw: `Feri inaenda Zanzibar?`, pl: `Czy prom płynie na Zanzibar?`, ipa: `fe-ri i-na-en-da zan-zi-bar`},{sw: `Ninakwenda Mombasa.`, pl: `Jadę do Mombasy.`, ipa: `ni-na-kwen-da mom-ba-sa`},{sw: `Safari ni ndefu?`, pl: `Czy podróż jest długa?`, ipa: `sa-fa-ri ni n-de-fu`}], grammar: `„Cha” w „kituo cha basi” łączy rzeczowniki i oznacza „przystanek autobusowy”. Czas teraźniejszy często ma cząstkę „na”, np. „linaondoka” — odjeżdża. „Ninakwenda” jest podobne do „naenda” i znaczy „idę / jadę”.`, practice: [`Zapytaj, gdzie jest przystanek autobusowy.`,`Kup jeden bilet.`,`Zapytaj, kiedy odjeżdża autobus.`,`Zapytaj, czy prom płynie na Zanzibar.`,`Powiedz, że jedziesz do Mombasy.`]},{day: 19, title: `Zwiedzanie i atrakcje`, title_native: `Kutembelea vivutio`, focus: `Nauczysz się mówić o zwiedzaniu, biletach wstępu i miejscach turystycznych. Przyda się to w muzeum, parku narodowym, na wycieczce po Stone Town albo przy plaży.`, vocab: [{sw: `kutembelea`, pl: `zwiedzać / odwiedzać`, ipa: `ku-tem-be-le-a`},{sw: `makumbusho`, pl: `muzeum`, ipa: `ma-kum-bu-szo`},{sw: `hifadhi`, pl: `park / rezerwat`, ipa: `hi-fa-dhi`},{sw: `pwani`, pl: `plaża / wybrzeże`, ipa: `pwa-ni`},{sw: `mwongozo`, pl: `przewodnik`, ipa: `m-won-go-zo`},{sw: `picha`, pl: `zdjęcie`, ipa: `pi-cza`},{sw: `tiketi`, pl: `bilet`, ipa: `ti-ke-ti`},{sw: `kiingilio`, pl: `opłata za wstęp`, ipa: `ki-in-gi-li-o`},{sw: `ramani`, pl: `mapa`, ipa: `ra-ma-ni`},{sw: `mahali`, pl: `miejsce`, ipa: `ma-ha-li`}], phrases: [{sw: `Nataka kutembelea makumbusho.`, pl: `Chcę zwiedzić muzeum.`, ipa: `na-ta-ka ku-tem-be-le-a ma-kum-bu-szo`},{sw: `Kiingilio ni kiasi gani?`, pl: `Ile kosztuje wstęp?`, ipa: `ki-in-gi-li-o ni ki-a-si ga-ni`},{sw: `Naweza kupiga picha?`, pl: `Czy mogę zrobić zdjęcie?`, ipa: `na-we-za ku-pi-ga pi-cza`},{sw: `Nahitaji ramani.`, pl: `Potrzebuję mapy.`, ipa: `na-hi-ta-dżi ra-ma-ni`},{sw: `Mwongozo yuko wapi?`, pl: `Gdzie jest przewodnik?`, ipa: `m-won-go-zo ju-ko wa-pi`},{sw: `Mahali hapa ni pazuri.`, pl: `To miejsce jest piękne.`, ipa: `ma-ha-li ha-pa ni pa-zu-ri`}], grammar: `„Naweza...?” oznacza „czy mogę...?” i jest bardzo praktyczne w muzeach, świątyniach i miejscach prywatnych. „Kupiga picha” dosłownie znaczy „robić zdjęcie”. Warto pytać o zgodę, bo w niektórych miejscach fotografowanie może być ograniczone.`, practice: [`Powiedz, że chcesz zwiedzić muzeum.`,`Zapytaj, ile kosztuje wstęp.`,`Zapytaj, czy możesz zrobić zdjęcie.`,`Powiedz, że potrzebujesz mapy.`,`Powiedz, że to miejsce jest piękne.`]},{day: 20, title: `Pogoda i ubrania`, title_native: `Hali ya hewa na nguo`, focus: `Nauczysz się mówić o pogodzie i ubraniach. To przyda się podczas planowania dnia na plaży, safari, spaceru po mieście albo rejsu promem.`, vocab: [{sw: `hali ya hewa`, pl: `pogoda`, ipa: `ha-li ja he-wa`},{sw: `jua`, pl: `słońce`, ipa: `dżu-a`},{sw: `mvua`, pl: `deszcz`, ipa: `m-vu-a`},{sw: `upepo`, pl: `wiatr`, ipa: `u-pe-po`},{sw: `joto`, pl: `upał / ciepło`, ipa: `dżo-to`},{sw: `baridi`, pl: `zimno`, ipa: `ba-ri-di`},{sw: `nguo`, pl: `ubrania`, ipa: `n-gu-o`},{sw: `kofia`, pl: `kapelusz / czapka`, ipa: `ko-fi-a`},{sw: `viatu`, pl: `buty`, ipa: `vi-a-tu`},{sw: `miwani`, pl: `okulary`, ipa: `mi-wa-ni`}], phrases: [{sw: `Leo kuna jua.`, pl: `Dzisiaj jest słońce.`, ipa: `le-o ku-na dżu-a`},{sw: `Mvua inanyesha.`, pl: `Pada deszcz.`, ipa: `m-vu-a i-na-nje-sza`},{sw: `Kuna joto sana.`, pl: `Jest bardzo gorąco.`, ipa: `ku-na dżo-to sa-na`},{sw: `Nahitaji kofia.`, pl: `Potrzebuję kapelusza.`, ipa: `na-hi-ta-dżi ko-fi-a`},{sw: `Viatu hivi ni vizuri.`, pl: `Te buty są dobre.`, ipa: `vi-a-tu hi-vi ni vi-zu-ri`},{sw: `Hali ya hewa ikoje?`, pl: `Jaka jest pogoda?`, ipa: `ha-li ja he-wa i-ko-dże`}], grammar: `„Kuna” pomaga mówić o warunkach: „kuna jua”, „kuna joto”, „kuna upepo”. „Inanyesha” oznacza „pada”, najczęściej w odniesieniu do deszczu. Przy ubraniach zapamiętaj „hivi” jako „te” dla wielu rzeczy, np. „viatu hivi” — te buty.`, practice: [`Powiedz, że dzisiaj jest słońce.`,`Powiedz, że pada deszcz.`,`Powiedz, że jest bardzo gorąco.`,`Powiedz, że potrzebujesz kapelusza.`,`Zapytaj, jaka jest pogoda.`]},{day: 21, title: `Zdrowie i apteka`, title_native: `Afya na duka la dawa`, focus: `Nauczysz się zgłaszać podstawowe dolegliwości i kupować leki w aptece. To ważne podczas każdej podróży, zwłaszcza w nowym klimacie i przy zmianie jedzenia.`, vocab: [{sw: `afya`, pl: `zdrowie`, ipa: `a-fja`},{sw: `duka la dawa`, pl: `apteka`, ipa: `du-ka la da-wa`},{sw: `dawa`, pl: `lek`, ipa: `da-wa`},{sw: `maumivu`, pl: `ból`, ipa: `ma-u-mi-vu`},{sw: `kichwa`, pl: `głowa`, ipa: `ki-czła`},{sw: `tumbo`, pl: `brzuch`, ipa: `tum-bo`},{sw: `homa`, pl: `gorączka`, ipa: `ho-ma`},{sw: `mgonjwa`, pl: `chory`, ipa: `m-gon-dżwa`},{sw: `daktari`, pl: `lekarz`, ipa: `dak-ta-ri`},{sw: `maji`, pl: `woda`, ipa: `ma-dżi`}], phrases: [{sw: `Ninaumwa.`, pl: `Źle się czuję / jestem chory.`, ipa: `ni-na-u-mwa`},{sw: `Nina maumivu ya kichwa.`, pl: `Boli mnie głowa.`, ipa: `ni-na ma-u-mi-vu ja ki-czła`},{sw: `Nina maumivu ya tumbo.`, pl: `Boli mnie brzuch.`, ipa: `ni-na ma-u-mi-vu ja tum-bo`},{sw: `Nahitaji duka la dawa.`, pl: `Potrzebuję apteki.`, ipa: `na-hi-ta-dżi du-ka la da-wa`},{sw: `Nahitaji daktari.`, pl: `Potrzebuję lekarza.`, ipa: `na-hi-ta-dżi dak-ta-ri`},{sw: `Naomba dawa hii.`, pl: `Poproszę ten lek.`, ipa: `na-om-ba da-wa hi-i`}], grammar: `„Nina maumivu ya...” oznacza „mam ból...” i możesz dodać część ciała. „Ninaumwa” to ogólne „źle się czuję”. W sytuacjach zdrowotnych mów krótko i jasno, a jeśli sprawa jest poważna, użyj „Nahitaji daktari”.`, practice: [`Powiedz, że źle się czujesz.`,`Powiedz, że boli cię głowa.`,`Powiedz, że boli cię brzuch.`,`Zapytaj o aptekę.`,`Powiedz, że potrzebujesz lekarza.`]},{day: 22, title: `Nagłe sytuacje`, title_native: `Dharura`, focus: `Nauczysz się podstawowych zwrotów na wypadek nagłej sytuacji. To słownictwo warto znać, nawet jeśli masz nadzieję nigdy go nie używać.`, vocab: [{sw: `dharura`, pl: `nagła sytuacja`, ipa: `dha-ru-ra`},{sw: `msaada`, pl: `pomoc`, ipa: `m-sa-a-da`},{sw: `polisi`, pl: `policja`, ipa: `po-li-si`},{sw: `hatari`, pl: `niebezpieczeństwo`, ipa: `ha-ta-ri`},{sw: `wizi`, pl: `kradzież`, ipa: `wi-zi`},{sw: `kupotea`, pl: `zgubić się`, ipa: `ku-po-te-a`},{sw: `simu`, pl: `telefon`, ipa: `si-mu`},{sw: `hospitali`, pl: `szpital`, ipa: `hos-pi-ta-li`},{sw: `haraka`, pl: `szybko`, ipa: `ha-ra-ka`},{sw: `salama`, pl: `bezpieczny`, ipa: `sa-la-ma`}], phrases: [{sw: `Msaada!`, pl: `Pomocy!`, ipa: `m-sa-a-da`},{sw: `Nahitaji polisi.`, pl: `Potrzebuję policji.`, ipa: `na-hi-ta-dżi po-li-si`},{sw: `Nimepotea.`, pl: `Zgubiłem się / zgubiłam się.`, ipa: `ni-me-po-te-a`},{sw: `Simu yangu imepotea.`, pl: `Mój telefon zaginął.`, ipa: `si-mu jan-gu i-me-po-te-a`},{sw: `Kuna hatari.`, pl: `Jest niebezpieczeństwo.`, ipa: `ku-na ha-ta-ri`},{sw: `Nipeleke hospitali, tafadhali.`, pl: `Proszę zawieźć mnie do szpitala.`, ipa: `ni-pe-le-ke hos-pi-ta-li ta-fa-dha-li`}], grammar: `„Nime...” często oznacza czynność zakończoną, np. „nimepotea” — zgubiłem się. „Yangu” ponownie oznacza „mój”, jak w „simu yangu”. W nagłej sytuacji ważniejsza jest zrozumiałość niż pełne zdania; jedno słowo „Msaada!” może wystarczyć.`, practice: [`Powiedz głośno: „Pomocy!”`,`Powiedz, że potrzebujesz policji.`,`Powiedz, że się zgubiłeś / zgubiłaś.`,`Powiedz, że twój telefon zaginął.`,`Poproś, żeby ktoś zawiózł cię do szpitala.`]},{day: 23, title: `Rozmowy towarzyskie`, title_native: `Mazungumzo ya kijamii`, focus: `Nauczysz się prowadzić prostą, miłą rozmowę z lokalną osobą. To przyda się w kawiarni, podczas wycieczki, w pensjonacie albo na plaży.`, vocab: [{sw: `mazungumzo`, pl: `rozmowa`, ipa: `ma-zun-gum-zo`},{sw: `rafiki`, pl: `przyjaciel`, ipa: `ra-fi-ki`},{sw: `kazi`, pl: `praca`, ipa: `ka-zi`},{sw: `nyumbani`, pl: `w domu / do domu`, ipa: `nju-mba-ni`},{sw: `kupenda`, pl: `lubić`, ipa: `ku-pen-da`},{sw: `muziki`, pl: `muzyka`, ipa: `mu-zi-ki`},{sw: `mchezo`, pl: `gra / sport`, ipa: `m-cze-zo`},{sw: `kusafiri`, pl: `podróżować`, ipa: `ku-sa-fi-ri`},{sw: `nzuri`, pl: `dobry`, ipa: `nzu-ri`},{sw: `karibu`, pl: `zapraszam / witaj`, ipa: `ka-ri-bu`}], phrases: [{sw: `Unafanya kazi gani?`, pl: `Jaką pracę wykonujesz?`, ipa: `u-na-fa-nja ka-zi ga-ni`},{sw: `Napenda kusafiri.`, pl: `Lubię podróżować.`, ipa: `na-pen-da ku-sa-fi-ri`},{sw: `Unapenda muziki?`, pl: `Lubisz muzykę?`, ipa: `u-na-pen-da mu-zi-ki`},{sw: `Ninatoka Polandi.`, pl: `Pochodzę z Polski.`, ipa: `ni-na-to-ka po-lan-di`},{sw: `Nimefurahi kuzungumza nawe.`, pl: `Miło było z tobą porozmawiać.`, ipa: `ni-me-fu-ra-hi ku-zun-gum-za na-we`},{sw: `Karibu Polandi.`, pl: `Zapraszam do Polski.`, ipa: `ka-ri-bu po-lan-di`}], grammar: `„Una...” w pytaniu często oznacza „czy ty...?”, np. „Unapenda muziki?” — lubisz muzykę? „Kuzungumza” znaczy „rozmawiać”. W rozmowie towarzyskiej dobrze jest odwzajemniać pytania i używać „asante” oraz „nimefurahi”.`, practice: [`Powiedz, że lubisz podróżować.`,`Zapytaj rozmówcę, czy lubi muzykę.`,`Powiedz, że pochodzisz z Polski.`,`Zapytaj, jaką pracę ktoś wykonuje.`,`Zakończ rozmowę zdaniem: „Miło było z tobą porozmawiać.”`]},{day: 24, title: `Telefon, internet i Wi-Fi`, title_native: `Simu, intaneti na Wi-Fi`, focus: `Nauczysz się pytać o internet, kartę SIM i ładowanie telefonu. To bardzo praktyczne po przylocie oraz podczas pracy zdalnej lub planowania trasy.`, vocab: [{sw: `simu`, pl: `telefon`, ipa: `si-mu`},{sw: `intaneti`, pl: `internet`, ipa: `in-ta-ne-ti`},{sw: `Wi-Fi`, pl: `Wi-Fi`, ipa: `łaj-faj`},{sw: `nywila`, pl: `hasło`, ipa: `nju-wi-la`},{sw: `chaja`, pl: `ładowarka`, ipa: `cza-dża`},{sw: `betri`, pl: `bateria`, ipa: `be-tri`},{sw: `duka`, pl: `sklep`, ipa: `du-ka`},{sw: `kadi ya SIM`, pl: `karta SIM`, ipa: `ka-di ja sim`},{sw: `kifurushi`, pl: `pakiet`, ipa: `ki-fu-ru-szi`},{sw: `mtandao`, pl: `sieć`, ipa: `m-tan-da-o`}], phrases: [{sw: `Wi-Fi iko?`, pl: `Czy jest Wi-Fi?`, ipa: `łaj-faj i-ko`},{sw: `Nywila ni nini?`, pl: `Jakie jest hasło?`, ipa: `nju-wi-la ni ni-ni`},{sw: `Nahitaji chaja.`, pl: `Potrzebuję ładowarki.`, ipa: `na-hi-ta-dżi cza-dża`},{sw: `Betri yangu imeisha.`, pl: `Moja bateria się wyczerpała.`, ipa: `be-tri jan-gu i-me-i-sza`},{sw: `Naomba kadi ya SIM.`, pl: `Poproszę kartę SIM.`, ipa: `na-om-ba ka-di ja sim`},{sw: `Kifurushi cha intaneti ni kiasi gani?`, pl: `Ile kosztuje pakiet internetu?`, ipa: `ki-fu-ru-szi cza in-ta-ne-ti ni ki-a-si ga-ni`}], grammar: `„Iko?” to krótkie i bardzo praktyczne pytanie: „czy jest?”. „Nywila ni nini?” dosłownie znaczy „hasło jest czym?”. W Tanzanii i Kenii pakiety danych są bardzo popularne, więc „kifurushi cha intaneti” to przydatny zwrot.`, practice: [`Zapytaj, czy jest Wi-Fi.`,`Zapytaj o hasło.`,`Powiedz, że potrzebujesz ładowarki.`,`Powiedz, że bateria się wyczerpała.`,`Zapytaj o cenę pakietu internetu.`]},{day: 25, title: `Plaża i wypoczynek`, title_native: `Pwani na mapumziko`, focus: `Nauczysz się słów związanych z plażą, odpoczynkiem i prostymi aktywnościami. To idealne na Zanzibar, wybrzeże Kenii lub okolice jeziora Wiktorii.`, vocab: [{sw: `pwani`, pl: `plaża / wybrzeże`, ipa: `pwa-ni`},{sw: `bahari`, pl: `morze`, ipa: `ba-ha-ri`},{sw: `mchanga`, pl: `piasek`, ipa: `m-czan-ga`},{sw: `jua`, pl: `słońce`, ipa: `dżu-a`},{sw: `kuogelea`, pl: `pływać`, ipa: `ku-o-ge-le-a`},{sw: `kupumzika`, pl: `odpoczywać`, ipa: `ku-pum-zi-ka`},{sw: `kivuli`, pl: `cień`, ipa: `ki-vu-li`},{sw: `mawimbi`, pl: `fale`, ipa: `ma-wim-bi`},{sw: `salama`, pl: `bezpieczny`, ipa: `sa-la-ma`},{sw: `mashua`, pl: `łódź`, ipa: `ma-szu-a`}], phrases: [{sw: `Nataka kwenda pwani.`, pl: `Chcę iść na plażę.`, ipa: `na-ta-ka kwen-da pwa-ni`},{sw: `Bahari ni nzuri.`, pl: `Morze jest piękne.`, ipa: `ba-ha-ri ni nzu-ri`},{sw: `Naweza kuogelea hapa?`, pl: `Czy mogę tu pływać?`, ipa: `na-we-za ku-o-ge-le-a ha-pa`},{sw: `Nahitaji kivuli.`, pl: `Potrzebuję cienia.`, ipa: `na-hi-ta-dżi ki-vu-li`},{sw: `Mawimbi ni makubwa.`, pl: `Fale są duże.`, ipa: `ma-wim-bi ni ma-ku-bwa`},{sw: `Ni salama?`, pl: `Czy to bezpieczne?`, ipa: `ni sa-la-ma`}], grammar: `„Kwenda” znaczy „iść / jechać”, a „nataka kwenda” — „chcę iść / jechać”. „Naweza” oznacza „mogę”, więc „Naweza kuogelea hapa?” to grzeczne pytanie o pozwolenie i bezpieczeństwo. Na plaży zawsze warto zapytać „Ni salama?”`, practice: [`Powiedz, że chcesz iść na plażę.`,`Zapytaj, czy możesz tu pływać.`,`Powiedz, że potrzebujesz cienia.`,`Powiedz, że morze jest piękne.`,`Zapytaj, czy to bezpieczne.`]},{day: 26, title: `Safari i przyroda`, title_native: `Safari na mazingira`, focus: `Nauczysz się słów przydatnych podczas safari, wycieczki do parku narodowego lub obserwacji przyrody. Suahili jest szczególnie związane z kulturą safari w Tanzanii i Kenii.`, vocab: [{sw: `safari`, pl: `podróż / safari`, ipa: `sa-fa-ri`},{sw: `wanyama`, pl: `zwierzęta`, ipa: `wa-nja-ma`},{sw: `simba`, pl: `lew`, ipa: `sim-ba`},{sw: `tembo`, pl: `słoń`, ipa: `tem-bo`},{sw: `twiga`, pl: `żyrafa`, ipa: `twi-ga`},{sw: `ndege`, pl: `ptak / samolot`, ipa: `n-de-ge`},{sw: `hifadhi ya taifa`, pl: `park narodowy`, ipa: `hi-fa-dhi ja ta-i-fa`},{sw: `mwongozo`, pl: `przewodnik`, ipa: `m-won-go-zo`},{sw: `kamera`, pl: `aparat`, ipa: `ka-me-ra`},{sw: `kimya`, pl: `cisza`, ipa: `kim-ja`}], phrases: [{sw: `Tunaenda safari.`, pl: `Jedziemy na safari.`, ipa: `tu-na-en-da sa-fa-ri`},{sw: `Nataka kuona simba.`, pl: `Chcę zobaczyć lwa.`, ipa: `na-ta-ka ku-o-na sim-ba`},{sw: `Tembo wako wapi?`, pl: `Gdzie są słonie?`, ipa: `tem-bo wa-ko wa-pi`},{sw: `Tafadhali, kaa kimya.`, pl: `Proszę, bądź cicho.`, ipa: `ta-fa-dha-li ka-a kim-ja`},{sw: `Naweza kupiga picha?`, pl: `Czy mogę zrobić zdjęcie?`, ipa: `na-we-za ku-pi-ga pi-cza`},{sw: `Mwongozo ni mzuri.`, pl: `Przewodnik jest dobry.`, ipa: `m-won-go-zo ni m-zu-ri`}], grammar: `„Kuona” znaczy „widzieć / zobaczyć”, więc „nataka kuona...” to „chcę zobaczyć...”. „Tunaenda” znaczy „idziemy / jedziemy” jako „my”. W safari ważne są krótkie instrukcje, np. „kaa kimya” — bądź cicho.`, practice: [`Powiedz, że jedziecie na safari.`,`Powiedz, że chcesz zobaczyć lwa.`,`Zapytaj, gdzie są słonie.`,`Poproś kogoś, żeby był cicho.`,`Powiedz, że przewodnik jest dobry.`]},{day: 27, title: `Zaproszenia i umawianie się`, title_native: `Mialiko na kupanga miadi`, focus: `Nauczysz się proponować spotkanie, przyjąć zaproszenie albo grzecznie odmówić. Przyda się to przy poznawaniu ludzi w podróży i planowaniu wspólnych wyjść.`, vocab: [{sw: `mwaliko`, pl: `zaproszenie`, ipa: `m-wa-li-ko`},{sw: `kukutana`, pl: `spotkać się`, ipa: `ku-ku-ta-na`},{sw: `leo`, pl: `dzisiaj`, ipa: `le-o`},{sw: `kesho`, pl: `jutro`, ipa: `ke-szo`},{sw: `saa`, pl: `godzina`, ipa: `sa-a`},{sw: `mahali`, pl: `miejsce`, ipa: `ma-ha-li`},{sw: `pamoja`, pl: `razem`, ipa: `pa-mo-dża`},{sw: `sawa`, pl: `dobrze / okej`, ipa: `sa-wa`},{sw: `samahani`, pl: `przepraszam`, ipa: `sa-ma-ha-ni`},{sw: `labda`, pl: `może`, ipa: `lab-da`}], phrases: [{sw: `Tukutane kesho.`, pl: `Spotkajmy się jutro.`, ipa: `tu-ku-ta-ne ke-szo`},{sw: `Unataka kunywa kahawa?`, pl: `Chcesz napić się kawy?`, ipa: `u-na-ta-ka ku-nju-wa ka-ha-wa`},{sw: `Sawa, tutaonana.`, pl: `Dobrze, zobaczymy się.`, ipa: `sa-wa tu-ta-o-na-na`},{sw: `Samahani, siwezi leo.`, pl: `Przepraszam, dziś nie mogę.`, ipa: `sa-ma-ha-ni si-we-zi le-o`},{sw: `Labda kesho.`, pl: `Może jutro.`, ipa: `lab-da ke-szo`},{sw: `Tukutane saa mbili.`, pl: `Spotkajmy się o drugiej.`, ipa: `tu-ku-ta-ne sa-a m-bi-li`}], grammar: `„Tukutane” oznacza „spotkajmy się” i jest bardzo użyteczne przy planowaniu. „Siwezi” znaczy „nie mogę”. W kulturze rozmowy dobrze jest odmawiać łagodnie, np. „Samahani, siwezi leo. Labda kesho.”`, practice: [`Zaproponuj spotkanie jutro.`,`Zapytaj kogoś, czy chce napić się kawy.`,`Powiedz, że dziś nie możesz.`,`Zaproponuj: „Może jutro.”`,`Umów spotkanie o konkretnej godzinie.`]},{day: 28, title: `Opinie i emocje`, title_native: `Maoni na hisia`, focus: `Nauczysz się mówić, co ci się podoba, co jest piękne, trudne albo ciekawe. To pomoże ci prowadzić bardziej naturalne rozmowy z mieszkańcami i innymi podróżnymi.`, vocab: [{sw: `maoni`, pl: `opinie`, ipa: `ma-o-ni`},{sw: `hisia`, pl: `emocje`, ipa: `hi-si-a`},{sw: `furaha`, pl: `radość`, ipa: `fu-ra-ha`},{sw: `nzuri`, pl: `dobry / piękny`, ipa: `nzu-ri`},{sw: `mbaya`, pl: `zły`, ipa: `m-ba-ja`},{sw: `rahisi`, pl: `łatwy`, ipa: `ra-hi-si`},{sw: `ngumu`, pl: `trudny`, ipa: `n-gu-mu`},{sw: `ya kuvutia`, pl: `ciekawy`, ipa: `ja ku-vu-ti-a`},{sw: `napenda`, pl: `lubię`, ipa: `na-pen-da`},{sw: `nashangaa`, pl: `dziwię się / jestem zaskoczony`, ipa: `na-szan-ga-a`}], phrases: [{sw: `Napenda mahali hapa.`, pl: `Podoba mi się to miejsce.`, ipa: `na-pen-da ma-ha-li ha-pa`},{sw: `Ni nzuri sana.`, pl: `To jest bardzo piękne / dobre.`, ipa: `ni nzu-ri sa-na`},{sw: `Ni ngumu kidogo.`, pl: `To jest trochę trudne.`, ipa: `ni n-gu-mu ki-do-go`},{sw: `Ni rahisi.`, pl: `To jest łatwe.`, ipa: `ni ra-hi-si`},{sw: `Hii ni ya kuvutia.`, pl: `To jest ciekawe.`, ipa: `hi-i ni ja ku-vu-ti-a`},{sw: `Nina furaha.`, pl: `Jestem szczęśliwy / szczęśliwa.`, ipa: `ni-na fu-ra-ha`}], grammar: `Wiele opinii możesz wyrazić bardzo prosto przez „ni” plus przymiotnik: „ni nzuri”, „ni rahisi”, „ni ngumu”. „Kidogo” łagodzi wypowiedź i znaczy „trochę”. „Napenda” może oznaczać zarówno „lubię”, jak i „podoba mi się”.`, practice: [`Powiedz, że podoba ci się to miejsce.`,`Powiedz, że coś jest bardzo piękne.`,`Powiedz, że coś jest trochę trudne.`,`Powiedz, że coś jest ciekawe.`,`Powiedz, że jesteś szczęśliwy / szczęśliwa.`]},{day: 29, title: `Załatwianie spraw w mieście`, title_native: `Kushughulikia mambo mjini`, focus: `Nauczysz się słów potrzebnych przy codziennych sprawach: pralni, poczcie, sklepie i wymianie informacji. To praktyczna lekcja dla podróżnika zostającego w mieście kilka dni dłużej.`, vocab: [{sw: `mji`, pl: `miasto`, ipa: `m-dżi`},{sw: `duka`, pl: `sklep`, ipa: `du-ka`},{sw: `posta`, pl: `poczta`, ipa: `pos-ta`},{sw: `nguo`, pl: `ubrania`, ipa: `n-gu-o`},{sw: `kufua`, pl: `prać`, ipa: `ku-fu-a`},{sw: `huduma`, pl: `usługa`, ipa: `hu-du-ma`},{sw: `anwani`, pl: `adres`, ipa: `an-wa-ni`},{sw: `karatasi`, pl: `papier / dokument`, ipa: `ka-ra-ta-si`},{sw: `kalamu`, pl: `długopis`, ipa: `ka-la-mu`},{sw: `fungua`, pl: `otwierać`, ipa: `fun-gu-a`}], phrases: [{sw: `Duka linafungua lini?`, pl: `Kiedy sklep się otwiera?`, ipa: `du-ka li-na-fun-gu-a li-ni`},{sw: `Nahitaji kufua nguo.`, pl: `Potrzebuję wyprać ubrania.`, ipa: `na-hi-ta-dżi ku-fu-a n-gu-o`},{sw: `Posta iko wapi?`, pl: `Gdzie jest poczta?`, ipa: `pos-ta i-ko wa-pi`},{sw: `Naomba kalamu.`, pl: `Poproszę długopis.`, ipa: `na-om-ba ka-la-mu`},{sw: `Anwani ni hii.`, pl: `Adres jest tutaj.`, ipa: `an-wa-ni ni hi-i`},{sw: `Huduma hii ni kiasi gani?`, pl: `Ile kosztuje ta usługa?`, ipa: `hu-du-ma hi-i ni ki-a-si ga-ni`}], grammar: `„Kufua nguo” znaczy „prać ubrania” i jest przydatne przy dłuższych podróżach. „Linafungua” oznacza „otwiera się” dla rzeczownika takiego jak „duka”. „Hii” znaczy „to / ten” przy wielu rzeczownikach, np. „huduma hii” — ta usługa.`, practice: [`Zapytaj, kiedy sklep się otwiera.`,`Powiedz, że potrzebujesz wyprać ubrania.`,`Zapytaj, gdzie jest poczta.`,`Poproś o długopis.`,`Zapytaj, ile kosztuje ta usługa.`]},{day: 30, title: `Powtórka podróżnika`, title_native: `Marudio ya msafiri`, focus: `Ostatni dzień łączy najważniejsze sytuacje: hotel, jedzenie, transport, zakupy, zdrowie i rozmowę. Po tej lekcji powinieneś umieć przeżyć typowy dzień w kraju suahili, używając prostych zdań.`, vocab: [{sw: `msafiri`, pl: `podróżnik`, ipa: `m-sa-fi-ri`},{sw: `safari`, pl: `podróż`, ipa: `sa-fa-ri`},{sw: `msaada`, pl: `pomoc`, ipa: `m-sa-a-da`},{sw: `chakula`, pl: `jedzenie`, ipa: `cza-ku-la`},{sw: `maji`, pl: `woda`, ipa: `ma-dżi`},{sw: `hoteli`, pl: `hotel`, ipa: `ho-te-li`},{sw: `teksi`, pl: `taksówka`, ipa: `tek-si`},{sw: `bei`, pl: `cena`, ipa: `be-i`},{sw: `salama`, pl: `bezpieczny`, ipa: `sa-la-ma`},{sw: `asante`, pl: `dziękuję`, ipa: `a-san-te`}], phrases: [{sw: `Mimi ni msafiri kutoka Polandi.`, pl: `Jestem podróżnikiem z Polski.`, ipa: `mi-mi ni m-sa-fi-ri ku-to-ka po-lan-di`},{sw: `Nahitaji msaada kidogo.`, pl: `Potrzebuję trochę pomocy.`, ipa: `na-hi-ta-dżi m-sa-a-da ki-do-go`},{sw: `Naomba maji, tafadhali.`, pl: `Poproszę wodę.`, ipa: `na-om-ba ma-dżi ta-fa-dha-li`},{sw: `Ninatafuta hoteli yangu.`, pl: `Szukam mojego hotelu.`, ipa: `ni-na-ta-fu-ta ho-te-li jan-gu`},{sw: `Bei ni sawa.`, pl: `Cena jest w porządku.`, ipa: `be-i ni sa-wa`},{sw: `Asante sana kwa msaada.`, pl: `Bardzo dziękuję za pomoc.`, ipa: `a-san-te sa-na kwa m-sa-a-da`}], grammar: `Dzisiejsza powtórka pokazuje, jak łączyć znane elementy: „ninatafuta” — szukam, „nahitaji” — potrzebuję, „naomba” — proszę o. Nawet z prostych zdań możesz zbudować skuteczną komunikację. W suahili uprzejmość, cierpliwość i uśmiech bardzo pomagają w codziennych sytuacjach.`, practice: [`Przedstaw się jako podróżnik z Polski.`,`Poproś o trochę pomocy.`,`Zamów wodę.`,`Powiedz, że szukasz swojego hotelu.`,`Podziękuj komuś za pomoc.`]}];

var CONVERSATIONS_PL_SW = [{id: 1, title: `Zamawianie kawy w kawiarni`, scene: `Jesteś rano w małej kawiarni w Stone Town na Zanzibarze. Chcesz zamówić kawę, coś lekkiego do jedzenia i zapytać o Wi-Fi.`, lines: [{who: `them`, sw: `Karibu, ungependa nini?`, pl: `Witamy, co chcesz?`},{who: `you`, sw: `Naomba kahawa na maziwa, tafadhali.`, pl: `Poproszę kawę z mlekiem.`},{who: `them`, sw: `Unataka sukari?`, pl: `Chcesz cukier?`},{who: `you`, sw: `Hapana, bila sukari, asante.`, pl: `Nie, bez cukru, dziękuję.`},{who: `them`, sw: `Unataka chakula pia?`, pl: `Chcesz też jedzenie?`},{who: `you`, sw: `Ndiyo, naomba mkate na mayai mawili.`, pl: `Tak, poproszę chleb i dwa jajka.`},{who: `them`, sw: `Sawa, subiri kidogo.`, pl: `Dobrze, poczekaj chwilę.`},{who: `you`, sw: `Wi-Fi iko hapa?`, pl: `Czy jest tutaj Wi-Fi?`},{who: `them`, sw: `Ndiyo, nywila iko kwenye risiti.`, pl: `Tak, hasło jest na paragonie.`},{who: `you`, sw: `Asante sana.`, pl: `Bardzo dziękuję.`},{who: `them`, sw: `Karibu sana.`, pl: `Proszę bardzo.`}]},{id: 2, title: `Zameldowanie w hotelu`, scene: `Przyjeżdżasz wieczorem do hotelu w Aruszy przed wyjazdem na safari. W recepcji chcesz potwierdzić rezerwację, zapytać o pokój i dostać klucz.`, lines: [{who: `them`, sw: `Habari za jioni, karibu hotelini.`, pl: `Dobry wieczór, witamy w hotelu.`},{who: `you`, sw: `Habari, nina hifadhi.`, pl: `Dzień dobry, mam rezerwację.`},{who: `them`, sw: `Jina lako ni nani?`, pl: `Jakie jest twoje nazwisko?`},{who: `you`, sw: `Jina langu ni Kowalski.`, pl: `Moje nazwisko to Kowalski.`},{who: `them`, sw: `Ndiyo, tuna chumba chako.`, pl: `Tak, mamy twój pokój.`},{who: `you`, sw: `Chumba kina bafu?`, pl: `Czy pokój ma łazienkę?`},{who: `them`, sw: `Ndiyo, kina bafu na Wi-Fi.`, pl: `Tak, ma łazienkę i Wi-Fi.`},{who: `you`, sw: `Ufunguo uko wapi?`, pl: `Gdzie jest klucz?`},{who: `them`, sw: `Ufunguo wako uko hapa.`, pl: `Twój klucz jest tutaj.`},{who: `you`, sw: `Asante, nitalipa sasa?`, pl: `Dziękuję, czy zapłacę teraz?`},{who: `them`, sw: `Hapana, unaweza kulipa kesho.`, pl: `Nie, możesz zapłacić jutro.`}]},{id: 3, title: `Pytanie o drogę w mieście`, scene: `Spacerujesz po centrum Dar es Salaam i próbujesz znaleźć przystanek autobusowy. Zatrzymujesz lokalną osobę i prosisz o prostą wskazówkę.`, lines: [{who: `you`, sw: `Samahani, kituo cha basi kiko wapi?`, pl: `Przepraszam, gdzie jest przystanek autobusowy?`},{who: `them`, sw: `Kiko karibu, pale mbele.`, pl: `Jest blisko, tam dalej.`},{who: `you`, sw: `Niende moja kwa moja?`, pl: `Mam iść prosto?`},{who: `them`, sw: `Ndiyo, nenda moja kwa moja.`, pl: `Tak, idź prosto.`},{who: `you`, sw: `Kisha nigeuke wapi?`, pl: `Potem gdzie mam skręcić?`},{who: `them`, sw: `Geuka kushoto baada ya duka.`, pl: `Skręć w lewo za sklepem.`},{who: `you`, sw: `Ni mbali sana?`, pl: `Czy to bardzo daleko?`},{who: `them`, sw: `Hapana, dakika tano tu.`, pl: `Nie, tylko pięć minut.`},{who: `you`, sw: `Asante sana kwa msaada.`, pl: `Bardzo dziękuję za pomoc.`},{who: `them`, sw: `Karibu, safari njema.`, pl: `Proszę, dobrej drogi.`}]},{id: 4, title: `Obiad w lokalnej restauracji`, scene: `Jesteś w restauracji w Mombasie i chcesz spróbować lokalnego jedzenia. Pytasz o menu, zamawiasz ryż z rybą i prosisz o rachunek.`, lines: [{who: `them`, sw: `Karibu, kaa hapa.`, pl: `Witamy, usiądź tutaj.`},{who: `you`, sw: `Asante, naomba menyu.`, pl: `Dziękuję, poproszę menu.`},{who: `them`, sw: `Hii hapa menyu.`, pl: `Oto menu.`},{who: `you`, sw: `Kuna samaki leo?`, pl: `Czy dzisiaj jest ryba?`},{who: `them`, sw: `Ndiyo, kuna samaki na wali.`, pl: `Tak, jest ryba z ryżem.`},{who: `you`, sw: `Sawa, ninataka wali na samaki.`, pl: `Dobrze, chcę ryż z rybą.`},{who: `them`, sw: `Unataka pilipili?`, pl: `Chcesz chili?`},{who: `you`, sw: `Hapana, bila pilipili, tafadhali.`, pl: `Nie, bez chili, proszę.`},{who: `them`, sw: `Chakula kitakuja sasa.`, pl: `Jedzenie zaraz przyjdzie.`},{who: `you`, sw: `Asante, naomba maji pia.`, pl: `Dziękuję, poproszę też wodę.`},{who: `them`, sw: `Sawa kabisa.`, pl: `Jak najbardziej.`},{who: `you`, sw: `Baadaye naomba bili.`, pl: `Później poproszę rachunek.`}]},{id: 5, title: `Kupowanie biletu na prom`, scene: `Jesteś przy przystani w Dar es Salaam i chcesz kupić bilet na prom na Zanzibar. Musisz zapytać o cenę, godzinę odpłynięcia i miejsce wejścia.`, lines: [{who: `them`, sw: `Habari, unakwenda wapi?`, pl: `Dzień dobry, dokąd jedziesz?`},{who: `you`, sw: `Ninakwenda Zanzibar.`, pl: `Jadę na Zanzibar.`},{who: `them`, sw: `Unahitaji tiketi ngapi?`, pl: `Ile biletów potrzebujesz?`},{who: `you`, sw: `Naomba tiketi moja.`, pl: `Poproszę jeden bilet.`},{who: `them`, sw: `Tiketi ni shilingi elfu hamsini.`, pl: `Bilet kosztuje pięćdziesiąt tysięcy szylingów.`},{who: `you`, sw: `Feri inaondoka lini?`, pl: `Kiedy odpływa prom?`},{who: `them`, sw: `Inaondoka saa nne asubuhi.`, pl: `Odpływa o dziesiątej rano.`},{who: `you`, sw: `Ninaweza kulipa kwa kadi?`, pl: `Czy mogę zapłacić kartą?`},{who: `them`, sw: `Ndiyo, unaweza kulipa kwa kadi.`, pl: `Tak, możesz zapłacić kartą.`},{who: `you`, sw: `Mlango wa kuingia uko wapi?`, pl: `Gdzie jest wejście?`},{who: `them`, sw: `Uko pale kulia.`, pl: `Jest tam po prawej.`},{who: `you`, sw: `Asante sana.`, pl: `Bardzo dziękuję.`}]},{id: 6, title: `Zakupy na targu`, scene: `Jesteś na targu w Aruszy i chcesz kupić owoce. Rozmawiasz ze sprzedawcą, pytasz o cenę i uprzejmie negocjujesz.`, lines: [{who: `them`, sw: `Karibu, matunda mazuri!`, pl: `Zapraszam, dobre owoce!`},{who: `you`, sw: `Asante, bei ya embe ni kiasi gani?`, pl: `Dziękuję, ile kosztuje mango?`},{who: `them`, sw: `Embe moja ni shilingi elfu mbili.`, pl: `Jedno mango kosztuje dwa tysiące szylingów.`},{who: `you`, sw: `Hii ni ghali kidogo.`, pl: `To trochę drogo.`},{who: `them`, sw: `Unataka ngapi?`, pl: `Ile chcesz?`},{who: `you`, sw: `Nataka embe tatu.`, pl: `Chcę trzy mango.`},{who: `them`, sw: `Kwa tatu, shilingi elfu tano.`, pl: `Za trzy, pięć tysięcy szylingów.`},{who: `you`, sw: `Unaweza kupunguza bei kidogo?`, pl: `Czy możesz trochę obniżyć cenę?`},{who: `them`, sw: `Sawa, shilingi elfu nne.`, pl: `Dobrze, cztery tysiące szylingów.`},{who: `you`, sw: `Sawa, naomba mfuko pia.`, pl: `Dobrze, poproszę też torbę.`},{who: `them`, sw: `Haya, karibu tena.`, pl: `Proszę, zapraszam ponownie.`},{who: `you`, sw: `Asante sana.`, pl: `Bardzo dziękuję.`}]},{id: 7, title: `W aptece`, scene: `Po całym dniu zwiedzania w Nairobi boli cię głowa i szukasz apteki. Wchodzisz do apteki i prosisz o prosty lek oraz wodę.`, lines: [{who: `them`, sw: `Karibu, unahitaji nini?`, pl: `Witam, czego potrzebujesz?`},{who: `you`, sw: `Nina maumivu ya kichwa.`, pl: `Boli mnie głowa.`},{who: `them`, sw: `Una homa pia?`, pl: `Masz też gorączkę?`},{who: `you`, sw: `Hapana, sina homa.`, pl: `Nie, nie mam gorączki.`},{who: `them`, sw: `Unahitaji dawa ya maumivu?`, pl: `Potrzebujesz leku przeciwbólowego?`},{who: `you`, sw: `Ndiyo, naomba dawa hii.`, pl: `Tak, poproszę ten lek.`},{who: `them`, sw: `Kunywa na maji baada ya chakula.`, pl: `Weź z wodą po jedzeniu.`},{who: `you`, sw: `Naomba maji pia.`, pl: `Poproszę też wodę.`},{who: `them`, sw: `Sawa, yote ni shilingi elfu tatu.`, pl: `Dobrze, wszystko kosztuje trzy tysiące szylingów.`},{who: `you`, sw: `Nitalipa kwa pesa taslimu.`, pl: `Zapłacę gotówką.`},{who: `them`, sw: `Asante, pole sana.`, pl: `Dziękuję, dużo zdrowia.`},{who: `you`, sw: `Asante kwa msaada.`, pl: `Dziękuję za pomoc.`}]},{id: 8, title: `Mała rozmowa z lokalną osobą`, scene: `Siedzisz nad morzem w Zanzibarze i rozmawiasz z lokalną osobą po krótkiej wycieczce. Chcesz powiedzieć, skąd jesteś, co ci się podoba i zapytać o życie w okolicy.`, lines: [{who: `you`, sw: `Habari, mahali hapa ni pazuri sana.`, pl: `Cześć, to miejsce jest bardzo piękne.`},{who: `them`, sw: `Asante, karibu Zanzibar.`, pl: `Dziękuję, witamy na Zanzibarze.`},{who: `you`, sw: `Mimi ni kutoka Polandi.`, pl: `Jestem z Polski.`},{who: `them`, sw: `Polandi iko mbali sana?`, pl: `Czy Polska jest bardzo daleko?`},{who: `you`, sw: `Ndiyo, ni mbali, lakini napenda kusafiri.`, pl: `Tak, jest daleko, ale lubię podróżować.`},{who: `them`, sw: `Unapenda Zanzibar?`, pl: `Podoba ci się Zanzibar?`},{who: `you`, sw: `Ndiyo, napenda bahari na chakula.`, pl: `Tak, podoba mi się morze i jedzenie.`},{who: `them`, sw: `Chakula gani unapenda?`, pl: `Jakie jedzenie lubisz?`},{who: `you`, sw: `Napenda samaki na wali.`, pl: `Lubię rybę z ryżem.`},{who: `them`, sw: `Vizuri sana, hiyo ni chakula kizuri.`, pl: `Bardzo dobrze, to dobre jedzenie.`},{who: `you`, sw: `Nimefurahi kuzungumza nawe.`, pl: `Miło było z tobą porozmawiać.`},{who: `them`, sw: `Mimi pia, safari njema.`, pl: `Mnie też, dobrej podróży.`}]}];